  8→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
  9→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 10→import { buildSectionScene } from '@/sections/scene';
 11→
 12→const PLAN_PADDING = 1500;
 13→const VERTICAL_PADDING = 700;
 14→const TOP_PADDING = 1100;
 15→
 16→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 17→  if (!points.length) return fallback;
 18→  return {
 19→    minX: Math.min(...points.map((point) => point.x)),
 20→    maxX: Math.max(...points.map((point) => point.x)),
 21→    minY: Math.min(...points.map((point) => point.y)),
 22→    maxY: Math.max(...points.map((point) => point.y)),
 23→  };
 24→}
 25→
 26→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 27→  return {
 28→    minX: bounds.minX - paddingX,
 29→    maxX: bounds.maxX + paddingX,
 30→    minY: bounds.minY - paddingY,
 31→    maxY: bounds.maxY + paddingY,
 32→  };
 33→}
 34→
 35→function collectPlanPoints(floor) {
 36→  const points = [];
 37→
 38→  for (const wall of floor.walls || []) {
 39→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 40→  }
 41→  for (const room of floor.rooms || []) {
 42→    points.push(...(room.points || []));
 43→  }
 44→  for (const beam of floor.beams || []) {
 45→    const renderData = getBeamRenderData(beam, floor.columns || []);
 46→    if (renderData?.outline) points.push(...renderData.outline);
 47→  }
 48→  for (const stair of floor.stairs || []) {
 49→    const renderData = getStairRenderData(stair);
 50→    if (renderData?.outline) points.push(...renderData.outline);
 51→  }
 52→  for (const column of floor.columns || []) {
 53→    points.push(...columnOutline(column));
 54→  }
 55→  if (floor.slab) {
 56→    points.push(...(getSlabRenderData(floor.slab)?.boundaryPoints || []));
 57→  }
 58→  if (floor.sectionCut) {
 59→    points.push(floor.sectionCut.startPoint, floor.sectionCut.endPoint);
 60→    const renderData = getSectionCutRenderData(floor.sectionCut);
 61→    if (renderData?.arrow) {
 62→      points.push(renderData.arrow.tip, renderData.arrow.left, renderData.arrow.right);
 63→    }
 64→  }
 65→
 66→  for (const door of floor.doors || []) {
 67→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 68→    if (!wall) continue;
 69→    const outline = doorOutlineOnWall(wall, door);
 70→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 71→  }
 72→
 73→  for (const windowItem of floor.windows || []) {
 74→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 75→    if (!wall) continue;
 76→    const outline = windowOutlineOnWall(wall, windowItem);
 77→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 78→  }
 79→
 80→  return points;
 81→}
 82→
 83→function buildPlanSource(floor) {
 84→  if (!floor) {
 85→    return {
 86→      kind: 'empty',
 87→      title: 'Plan',
 88→      message: 'Missing floor.',
 89→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
 90→    };
 91→  }
 92→
 93→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
 94→
 95→  return {
 96→    kind: 'plan',
 97→    title: `${floor.name} Plan`,
 98→    floor,
 99→    bounds: geometryBounds,
100→  };
101→}
102→
103→function sceneBoundsToRenderBounds(scene) {
104→  return {
105→    minX: scene.bounds.minX - VERTICAL_PADDING,
106→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
107→    minY: -scene.bounds.maxZ - TOP_PADDING,
108→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
109→  };
110→}
111→
112→function buildSectionSource(floor, sourceRefId) {
113→  if (!floor?.sectionCut) {
114→    return {
115→      kind: 'empty',
116→      title: 'Section',
117→      message: 'No section cut on this floor.',
118→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
119→    };
120→  }
121→
122→  if (sourceRefId && floor.sectionCut.id !== sourceRefId) {
123→    return {
124→      kind: 'empty',
125→      title: 'Section',
126→      message: 'Section source not found.',
127→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
128→    };
129→  }
130→
131→  const scene = buildSectionScene(floor);
132→  return {
133→    kind: 'section',
134→    title: floor.sectionCut.label || 'Section',
135→    floor,
136→    scene,
137→    bounds: sceneBoundsToRenderBounds(scene),
138→  };
139→}
140→
141→function buildElevationSource(floor, sourceView) {
142→  if (!floor) {
143→    return {
144→      kind: 'empty',
145→      title: 'Elevation',
146→      message: 'Missing floor.',
147→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
148→    };
149→  }
150→
151→  const scene = buildElevationScene(floor, sourceView);
152→  const annotationScene = buildElevationAnnotationScene(floor, scene);
153→
154→  return {
155→    kind: 'elevation',
156→    title: scene.title,
157→    floor,
158→    viewMode: sourceView,
159→    scene,
160→    annotationScene,
161→    bounds: sceneBoundsToRenderBounds(scene),
162→  };
163→}
164→
165→export function resolveSheetViewportSource(project, viewport) {
166→  const floor = (project.floors || []).find((entry) => entry.id === viewport.sourceFloorId)
167→    || project.floors?.[0]
168→    || null;
169→
170→  switch (viewport.sourceView) {
171→    case 'section':
172→      return buildSectionSource(floor, viewport.sourceRefId);
173→    case 'elevation_front':
174→    case 'elevation_rear':
175→    case 'elevation_left':
176→    case 'elevation_right':
177→      return buildElevationSource(floor, viewport.sourceView);
178→    case 'plan':
179→    default:
180→      return buildPlanSource(floor);
181→  }
182→}
