107→export function resolveColumnAttachmentPoint(column, attachment) {
108→  if (!column || !attachment) return null;
109→
110→  if (attachment.featureType === 'corner') {
111→    const corners = columnOutline(column);
112→    return corners[attachment.featureIndex] ? { ...corners[attachment.featureIndex] } : null;
113→  }
114→
115→  if (attachment.featureType === 'face') {
116→    const face = columnFaces(column).find((entry) => entry.index === attachment.featureIndex);
117→    if (!face) return null;
118→    const clamped = Math.max(-face.length / 2, Math.min(face.length / 2, attachment.offset || 0));
119→    return add(face.midpoint, scale(face.tangent, clamped));
120→  }
121→
122→  if (attachment.featureType === 'centerline') {
123→    const centerline = columnCenterlines(column).find((entry) => entry.index === attachment.featureIndex);
124→    if (!centerline) return null;
125→    return add(columnCenter(column), scale(centerline.axis, attachment.offset || 0));
126→  }
127→
128→  return null;
129→}
